{"code": "import json

# Get company info
stockinfo_results = locals()['var_functions.query_db:12']

# Process company descriptions to get cleaner company names
def clean_company_name(description):
    # Remove "specializes in..." part and clean up
    parts = description.split(' specializes')
    name = parts[0].strip()
    # Remove trailing commas or phrases
    if name.endswith(', based in Canada,'):
        name = name.replace(', based in Canada,', '')
    if name.endswith(' offers investors a unique opportunity'):
        name = name.split(' offers')[0]
    if name.endswith(' provides telecommunications services'):
        name = name.split(' provides')[0]
    if name.endswith(' specializes'):
        name = name.replace(' specializes', '')
    if name.endswith(' harnesses the power'):
        name = name.split(' harnesses')[0]
    if name.endswith(' is at the forefront'):
        name = name.split(' is')[0]
    if name.endswith(' is dedicated'):
        name = name.split(' is')[0]
    if name.endswith(' is an investment company'):
        name = name.split(' is')[0]
    if name.endswith(' is an online luxury marketplace'):
        name = name.split(' is')[0]
    return name

company_mapping = {}
for row in stockinfo_results:
    symbol = row['Symbol']
    company_name = clean_company_name(row['Company Description'])
    company_mapping[symbol] = {
        'company_name': company_name,
        'financial_status': row['Financial Status'],
        'market_category': row['Market Category']
    }

print('__RESULT__:')
print(json.dumps({
    'total_companies': len(company_mapping),
    'companies': company_mapping
}, indent=2))"}

